 3→import { AGENT_IDS } from "../types.js";
 4→export function loadManifest(directory) {
 5→    const manifestPath = path.join(directory, "inception.json");
 6→    let raw;
 7→    try {
 8→        raw = readFileSync(manifestPath, "utf-8");
 9→    }
10→    catch {
11→        throw new Error(`No inception.json found in ${directory}. Are you pointing to the right repo?`);
12→    }
13→    let parsed;
14→    try {
15→        parsed = JSON.parse(raw);
16→    }
17→    catch {
18→        throw new Error(`Invalid JSON in ${manifestPath}`);
19→    }
20→    return validateManifest(parsed, manifestPath);
21→}
22→function validateManifest(data, filePath) {
23→    if (typeof data !== "object" || data === null || Array.isArray(data)) {
24→        throw new Error(`${filePath}: manifest must be a JSON object`);
25→    }
26→    const obj = data;
27→    if (!Array.isArray(obj.skills)) {
28→        throw new Error(`${filePath}: "skills" must be an array`);
29→    }
30→    const skills = obj.skills.map((entry, i) => {
31→        if (typeof entry !== "object" || entry === null || Array.isArray(entry)) {
32→            throw new Error(`${filePath}: skills[${i}] must be an object`);
33→        }
34→        const skill = entry;
35→        if (typeof skill.name !== "string" || skill.name.length === 0) {
36→            throw new Error(`${filePath}: skills[${i}].name must be a non-empty string`);
37→        }
38→        if (typeof skill.path !== "string" || skill.path.length === 0) {
39→            throw new Error(`${filePath}: skills[${i}].path must be a non-empty string`);
40→        }
41→        if (!Array.isArray(skill.agents) || skill.agents.length === 0) {
42→            throw new Error(`${filePath}: skills[${i}].agents must be a non-empty array`);
43→        }
44→        for (const agent of skill.agents) {
45→            if (!AGENT_IDS.includes(agent)) {
46→                throw new Error(`${filePath}: skills[${i}].agents contains unknown agent "${agent}". Valid agents: ${AGENT_IDS.join(", ")}`);
47→            }
48→        }
49→        return {
50→            name: skill.name,
51→            path: skill.path,
52→            agents: skill.agents,
53→        };
54→    });
55→    return {
56→        skills,
57→        mcpServers: Array.isArray(obj.mcpServers) ? obj.mcpServers : [],
58→        agentRules: Array.isArray(obj.agentRules) ? obj.agentRules : [],
59→    };
60→}
